import React, { Component } from 'react';

class Navbar extends Component {
    render() {
        return (
            <div className="nav-container">
                <div className="logo"></div>
                <div className="menu">
                    <a href={this.props.ink}></a>
                </div>
            </div>
        );
    }
}

export default Navbar;
